INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Unlimited Event Types$q$, $q$Create as many booking page types as needed, even on the free single-user plan.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Round-Robin & Collective Team Scheduling$q$, $q$Distribute bookings evenly across a sales, support, or recruiting team, or book everyone at once for panel meetings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$100+ App Integrations$q$, $q$Connect calendars, video conferencing, payment processors (Stripe, PayPal), and CRMs (Salesforce, HubSpot).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Workflow Automation & Routing Forms$q$, $q$Trigger custom notifications and route leads to the right person based on form answers before a meeting is booked.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Developer API & Embeds$q$, $q$Build scheduling directly into your own product using Cal.com's API and embeddable widgets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Enterprise Compliance$q$, $q$SAML SSO, SCIM provisioning, and SOC 2, HIPAA, and ISO 27001 support on the Organizations and Enterprise tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Mobile Apps$q$, $q$Cal.com Companion apps for iOS and Android let users manage bookings and get push notifications.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Generous free tier with unlimited event types for individual users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Deep customization through its API, embeds, and (formerly fully open-source) codebase$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Wide integration library covering calendars, payments, and CRM tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Enterprise-grade compliance options (SOC 2, HIPAA, ISO 27001) at the Organizations tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Moved its core hosted product from open-source (AGPL) to a proprietary license in April 2026, disappointing parts of its self-hosting community$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Per-seat pricing on Teams and Organizations plans can add up for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Some advanced routing, SSO, and compliance features are gated behind higher-priced tiers$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Is Cal.com free?$q$, $q$Yes. The Free plan supports one user with unlimited event types, calendar connections, and access to 100+ integrations. Paid Teams and Organizations plans add team scheduling and enterprise features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Is Cal.com still open source?$q$, $q$Cal.com was originally built as an open-source (AGPL) project, but in April 2026 the company moved its main hosted product to a proprietary license, citing AI-related security concerns. It continues to maintain a smaller, MIT-licensed security component called Cal.diy.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$What is Cal.com used for?$q$, $q$Cal.com is used for booking one-on-one and team meetings, automating scheduling workflows, qualifying inbound leads with routing forms, and embedding scheduling into other products via its API.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Does Cal.com integrate with Zoom and Google Calendar?$q$, $q$Yes, Cal.com connects with Google Calendar, Outlook, Zoom, and more than 100 other apps, including Stripe, PayPal, Salesforce, and HubSpot.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Is there a Cal.com mobile app?$q$, $q$Yes. Cal.com Companion is available free for iOS and Android and lets users manage bookings and receive real-time notifications.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Sales & Recruiting Scheduling$q$, $q$Route inbound leads or candidates to the right rep or interviewer automatically using round-robin scheduling and routing forms.$q$, $q$Sales and talent teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Embedded Product Scheduling$q$, $q$Use Cal.com's API and embeddable widgets to add booking flows directly inside a SaaS product.$q$, $q$Developers and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Individual Meeting Booking$q$, $q$Freelancers and professionals share a personal booking link for client calls, consultations, or interviews.$q$, $q$Individual professionals and freelancers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 user","Unlimited event types & calendars","100+ app integrations","Mobile app","Stripe & PayPal payments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Teams$q$, $q$$12/month per user (billed annually)$q$, $q$annual (monthly billing also available)$q$, NULL, $q$["Team scheduling","Round-robin scheduling","Managed event types","Booking analytics","Custom APIs","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Organizations$q$, $q$$28/month per user (billed annually)$q$, $q$annual (monthly billing also available)$q$, NULL, $q$["Unlimited sub-teams","SAML SSO & SCIM","Company subdomain","SOC 2, HIPAA, ISO 27001","Role-based permissions","14-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Dedicated support","SLA guarantees","HRIS integrations","Dedicated database"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cal.com is a scheduling platform founded in 2021 by Peer Richelsen and Bailey Pumfleet, originally released as Calendso before the team acquired the Cal.com domain and rebranded. The San Francisco-based company built its reputation on a commercial open-source model, pairing a free, self-hostable core with paid cloud and enterprise plans.$q$, $q$In April 2026, Cal.com shifted its main hosted product to a proprietary license, citing the risk of AI tools scanning public repositories for vulnerabilities, while open-sourcing a security-focused component called Cal.diy under an MIT license. The move drew both attention and criticism from the open-source community it had built.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cal.com supports unlimited event types and booking pages, team-based round-robin and collective scheduling, workflow automation, and routing forms for qualifying leads before a meeting is booked.$q$, $q$It connects to more than 100 apps, including Google Calendar, Zoom, Stripe, PayPal, Salesforce, and HubSpot, and offers a public API plus embeddable booking widgets for developers who want to build scheduling directly into their own products. Native iOS and Android apps handle bookings and notifications on the go.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cal.com's Free plan covers one user with unlimited event types and 100+ integrations. Paid plans scale per user: Teams starts at $12/month per user (billed annually) with a 14-day trial, and Organizations starts at $28/month per user (billed annually) adding SSO, SCIM, and compliance features. Enterprise pricing is custom.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
