INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Rust-Based Architecture$q$, $q$Backend built in Rust rather than PHP, aimed at higher throughput and lower memory use than older panels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Docker-Isolated Servers$q$, $q$Each managed game server runs in its own Docker container for isolation and security.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Pterodactyl Egg Compatibility$q$, $q$Supports existing Pterodactyl egg presets and offers migration tooling for admins switching panels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Extensible Plugin System$q$, $q$A Rust-trait-based plugin architecture allows custom extensions on both frontend and backend.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Cross-Platform Panel$q$, $q$Runs on Windows, Linux, or Docker; the Wings server daemon requires Linux.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$ARM64 & Raspberry Pi Support$q$, $q$Runs on ARM64 hardware, making small home-lab deployments practical.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Completely free for personal and commercial use with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Rust-based backend aims for significantly lower memory and CPU overhead than PHP-based panels$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Compatible with existing Pterodactyl egg presets, easing migration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Extensible plugin system for custom functionality$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Young project (public since 2025) with a smaller community and track record than established panels$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Requires self-hosting plus working knowledge of Docker and Linux server administration$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$No official managed/cloud-hosted option; operators handle their own infrastructure$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Is Calagopus free?$q$, $q$Yes. Calagopus is free and open source for both personal and commercial use, with no feature gating or paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Is Calagopus self-hosted?$q$, $q$Yes. Calagopus must be self-hosted; the panel runs on Windows, Linux, or Docker, and the Wings server-side daemon requires a Linux host.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$How is Calagopus different from Pterodactyl?$q$, $q$Calagopus is a from-scratch reimplementation of a Pterodactyl-style panel written in Rust and React rather than PHP, aiming for better performance and a more extensible plugin system, while remaining compatible with existing Pterodactyl egg presets.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$What games can Calagopus manage?$q$, $q$Calagopus can manage Minecraft, Rust, and other Linux-containerized game servers supported through its egg system.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Game Server Hosting Businesses$q$, $q$Commercial hosting providers use Calagopus to deploy and manage many customer game servers with lower resource overhead.$q$, $q$Game server hosting companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$Homelab & Community Servers$q$, $q$Hobbyists and small gaming communities self-host Calagopus, including on low-power ARM64 hardware like Raspberry Pi, to run their own Minecraft or Rust servers.$q$, $q$Homelab enthusiasts and gaming communities$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Calagopus is an open-source, self-hosted panel for deploying and managing game servers such as Minecraft and Rust. It was written from scratch in Rust and React as a modern alternative to Pterodactyl Panel, a widely used PHP-based game server management tool, with the stated goals of better performance, a refreshed interface, and a more extensible plugin architecture.$q$, $q$The project has been publicly developed on GitHub since 2025 under the calagopus organization, with frequent point releases. It is free for personal and commercial use with no feature gating.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Each game server runs inside an isolated Docker container, and the panel supports Pterodactyl-compatible 'egg' presets so administrators can reuse existing game installation configurations. A Rust-trait-based plugin system lets developers extend both the frontend and backend.$q$, $q$The panel component runs on Windows, Linux, or Docker, while the Wings server-side daemon requires Linux; the project also supports ARM64 hardware, including Raspberry Pi.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Calagopus is entirely free and open source, with no paid tiers, subscriptions, or feature gating for personal or commercial deployments. Users are responsible for their own hosting infrastructure costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5950887b-56e9-4a05-b6d2-f57b3d882853', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Online Booking Pages$q$, $q$A shareable page listing services and pricing, distributed via link, QR code, or website embed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Calendar Sync$q$, $q$Automatic two-way sync with Google Calendar, Outlook, and Apple Calendar to prevent double-booking.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Automated Reminders$q$, $q$Email reminders sent 24 hours and 1 hour before each appointment to reduce no-shows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Client Records$q$, $q$Client history updates automatically after every visit for a running appointment log.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Stripe Payments$q$, $q$Clients can pay when booking or after service, with standard Stripe fees and no added Calday cut.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$iOS & Android Apps$q$, $q$Native mobile apps let providers manage bookings on the go.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Free plan with no credit card required and no trial timer$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Simple setup aimed specifically at solo providers and small businesses$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Native mobile apps for both iOS and Android$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$No added transaction fee on top of standard Stripe processing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Limited public information available about the company behind the product$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Feature set is narrower than larger platforms like Calendly or Cal.com (no team routing, API, or advanced compliance features)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Premium features require the $12/month plan$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Is Calday free?$q$, $q$Yes. Calday offers a Free plan for small businesses with no credit card required, plus a $12/month Premium plan for growing businesses.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Does Calday sync with Google Calendar?$q$, $q$Yes, Calday automatically syncs bookings with Google Calendar, Outlook, and Apple Calendar.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Can clients pay through Calday?$q$, $q$Yes, Calday integrates with Stripe so clients can pay when booking or after the appointment; only standard Stripe processing fees apply.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Is there a Calday mobile app?$q$, $q$Yes, Calday has native apps on the Apple App Store and Google Play for managing bookings from a phone.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Solo Service Providers$q$, $q$Therapists, tutors, coaches, and consultants use Calday to let clients self-book appointments and reduce no-shows with automated reminders.$q$, $q$Individual service professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Small Local Businesses$q$, $q$Salons and home-service businesses use Calday's booking page and calendar sync to manage client scheduling without manual coordination.$q$, $q$Small local businesses$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Online booking page","Calendar sync","Automated reminders","Client records"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$Premium$q$, $q$$12/month$q$, $q$monthly$q$, NULL, $q$["All Free features","Advanced booking and business tools"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Calday is a booking and client-management app built for solo service providers and small businesses — think consultants, tutors, therapists, coaches, salons, and home-service businesses. It bundles a shareable booking page, calendar sync, client records, automated reminders, and payment collection into one tool.$q$, $q$The app is available as a web app and as native iOS and Android apps, letting providers manage their schedule from a phone as well as a browser.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Providers create a booking page with their services and prices, then share it via link, QR code, or website embed. Every booking syncs automatically with Google Calendar, Outlook, and Apple Calendar, and clients receive automated reminder emails 24 hours and 1 hour before their appointment.$q$, $q$Calday connects to Stripe so clients can pay at booking or after the appointment, with only standard Stripe processing fees applied — Calday does not add its own cut.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Calday uses a simple two-tier model: a Free plan for small businesses with no credit card required, and a Premium plan for growing businesses at $12/month. Both are month-to-month with no long-term contract or cancellation fee.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('59765ae5-0390-4cfe-8c3d-77fc6b87aa0d', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
