INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Single & Group Event Types$q$, $q$Share booking links for one-on-one meetings or group sessions based on live calendar availability.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Round-Robin & Collective Scheduling$q$, $q$Distribute bookings evenly across a team or schedule panel meetings with multiple attendees.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Routing Forms$q$, $q$Qualify and direct inbound leads to the right team member before a meeting is booked.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Workflow Automation$q$, $q$Send automated reminders, confirmations, and follow-ups tied to booking events.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$CRM & Calendar Integrations$q$, $q$Connects with Google Calendar, Outlook, Zoom, Salesforce, and HubSpot.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Enterprise Security$q$, $q$SSO, audit logging, and the full Salesforce routing suite on the Enterprise plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Mobile Apps$q$, $q$Free iOS and Android apps available to users on every plan.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Market-leading brand recognition with a large integration ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Easy to set up for individuals with a generous free tier$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Strong team scheduling features (round-robin, collective, routing forms)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Enterprise-grade security and Salesforce routing for large organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Free plan is limited to a single event type and one connected calendar$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Per-seat pricing on Teams and Enterprise can add up quickly for larger organizations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Advanced routing and compliance features are reserved for the Enterprise tier$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Is Calendly free?$q$, $q$Yes. Calendly's Free plan supports one event type with unlimited meetings and a single connected calendar. Paid plans start with Standard at $10-12/month per seat.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Who founded Calendly?$q$, $q$Calendly was founded in 2013 by Tope Awotona in Atlanta, Georgia.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Does Calendly have a mobile app?$q$, $q$Yes, Calendly offers free iOS and Android apps available to users on any plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$What's the difference between Calendly Standard and Teams?$q$, $q$Standard is built for individuals with more scheduling flexibility, while Teams adds round-robin and collective scheduling for groups and starts at $16-20/month per seat.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Does Calendly integrate with Salesforce?$q$, $q$Yes, Calendly integrates with Salesforce, with the full Salesforce routing suite available on the Enterprise plan.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Sales Demo Booking$q$, $q$Sales teams use routing forms and round-robin scheduling to book demos and route leads to the right rep.$q$, $q$Sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Recruiting & Interview Scheduling$q$, $q$Recruiters share booking links so candidates can self-schedule interviews around interviewer availability.$q$, $q$Recruiting and HR teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Client Meeting Management$q$, $q$Consultants, coaches, and freelancers use a personal booking page to manage client meetings without email back-and-forth.$q$, $q$Individual professionals and freelancers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 event type","Unlimited meetings","1 connected calendar","Booking page customization","Mobile app & browser extension"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Standard$q$, $q$$10/month per seat (annual) or $12/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Multiple event types","More integrations","Group events"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Teams$q$, $q$$16/month per seat (annual) or $20/month (monthly), 1-30 seats$q$, $q$monthly or annual$q$, NULL, $q$["Round-robin scheduling","Collective scheduling","Routing forms","Team workflows"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["SSO","Audit logging","Dedicated implementation support","Full Salesforce routing suite"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Calendly was founded in 2013 in Atlanta, Georgia by Tope Awotona and grew into one of the most recognized names in online scheduling, reaching a reported $3 billion valuation and roughly 500 employees. The company moved to a remote-first model in 2021 after closing its Atlanta office.$q$, $q$Calendly lets users share a personal booking link so others can pick an open meeting time based on live calendar availability, eliminating manual back-and-forth scheduling emails.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond single-user booking links, Calendly supports round-robin and collective team scheduling, routing forms to qualify and direct inbound leads, and workflow automation for reminders and follow-ups.$q$, $q$It integrates with Google Calendar, Outlook, Zoom, Salesforce, and HubSpot, and is available via browser extension, embeddable widgets, and free iOS/Android apps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Calendly's Free plan supports one event type with unlimited meetings. Standard starts at $10/month per seat (annual billing), Teams starts at $16/month per seat (annual billing, 1-30 seats), and Enterprise pricing is custom for organizations needing SSO and audit logging.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a69c9e8e-2b63-4936-9731-f85ffcfa1860', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
