INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$E-Book Library Management$q$, $q$Organize a personal e-book collection with searchable, editable metadata.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Format Conversion$q$, $q$Convert between EPUB, MOBI, AZW3, PDF, and many other e-book formats.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Built-In Viewer & Editor$q$, $q$Read books and edit formatting, fonts, margins, and auto-generated tables of contents.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Automatic Metadata & Covers$q$, $q$Fetch book metadata and cover art from the internet automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Device Sync$q$, $q$Transfer and sync books to Kindle, Kobo, Nook, and other e-reader hardware.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$News & Periodical Download$q$, $q$Download online news sources and convert them into e-books for offline reading.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Self-Hosted Content Server$q$, $q$Optional server component for remote, browser-based access to a user's library.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Plugin Architecture$q$, $q$Extend functionality with community-built plugins.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Completely free and open source with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Extremely broad e-book format support and conversion quality$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Actively maintained since 2006 with regular updates$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Cross-platform on Windows, macOS, and Linux$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Interface is more utilitarian than modern consumer apps and has a learning curve for advanced features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$No official first-party mobile app for iOS or Android$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Primarily desktop-focused; remote access requires manually setting up the content server$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Is Calibre free?$q$, $q$Yes, calibre is completely free and open source with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Who created Calibre?$q$, $q$Calibre was created by Kovid Goyal, who first released it on October 31, 2006, initially to add Linux support for Sony's PRS-500 e-reader.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$What e-book formats does Calibre support?$q$, $q$Calibre supports converting between most major e-book formats, including EPUB, MOBI, AZW3, and PDF.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Does Calibre work with Kindle?$q$, $q$Yes, calibre can convert and sync e-books to Kindle devices, as well as Kobo, Nook, and other e-readers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Is Calibre available on Mac and Linux?$q$, $q$Yes, calibre is cross-platform and runs natively on Windows, macOS, and Linux.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Personal E-Book Library Management$q$, $q$Collectors use calibre to organize, tag, and convert large personal e-book libraries across formats and devices.$q$, $q$Personal e-book collectors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Self-Published Author Formatting$q$, $q$Independent authors use calibre to convert manuscripts between formats required by different retailers and devices.$q$, $q$Independent and self-published authors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$Institutional Digital Collections$q$, $q$Libraries and institutions use calibre's free, cross-platform tools and content server to manage and distribute digital text collections.$q$, $q$Libraries and institutions$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Calibre is a free, open-source e-book management application created by Kovid Goyal and first released on October 31, 2006, originally to work around the lack of Linux support for Sony's PRS-500 e-reader. It grew from a simple format converter into a full e-book library manager, renamed calibre in 2008.$q$, $q$Goyal, based in Mumbai, India, remains the lead developer alongside a small core team and a large volunteer community that has translated the software into more than a dozen languages. Calibre runs on Windows, macOS, and Linux.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Calibre manages a searchable e-book library with automatic metadata and cover fetching, converts books between formats like EPUB, MOBI, AZW3, and PDF, and includes a built-in viewer and editor for adjusting fonts, margins, and tables of contents.$q$, $q$It syncs books to Kindle, Kobo, Nook, and other e-reader devices, can download news sources and convert them into e-books, and offers an optional self-hosted content server for remote library access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Calibre is completely free and open source, with no paid tiers, subscriptions, or licensing fees for any of its features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3e99368f-6adc-431d-9ed6-588c0d07395e', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
