INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Drag-and-Drop Email Builder$q$, $q$Build campaigns with customizable templates without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$AI-Assisted Writing$q$, $q$AI email-writing tools to draft and refine campaign copy.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Marketing Automation Journeys$q$, $q$Trigger email sequences based on subscriber behavior and events.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Audience Segmentation$q$, $q$Target campaigns to specific subscriber segments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$A/B Testing$q$, $q$Test subject lines and content variations to optimize performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Transactional Email$q$, $q$Send order confirmations and other transactional messages (Lite plan and up).$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Send-Time Optimization$q$, $q$Automatically times sends for individual subscriber engagement (Premier plan).$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Campaign Analytics$q$, $q$Reporting on opens, clicks, and campaign performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Established platform with a long track record dating back to 2004$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Easy-to-use drag-and-drop builder suited to non-technical marketers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Unlimited sends on Essentials and higher tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$15% discount available for nonprofit organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Pricing scales with subscriber list size, which can get expensive for larger lists$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$The entry Lite plan caps monthly sends rather than offering unlimited sending$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Ownership changes (CM Group to Marigold, and the 2025 sale of the enterprise business to Zeta Global) have added brand confusion$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Fewer advanced e-commerce automation features than commerce-focused competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Is Campaign Monitor free?$q$, $q$Campaign Monitor offers a 30-day free trial supporting up to 500 contacts and 500 sends with limited reporting; ongoing use requires a paid Lite, Essentials, Premier, or Enterprise plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Who owns Campaign Monitor now?$q$, $q$Campaign Monitor is owned by Marigold, a marketing technology company formed in 2023 from the merger of CM Group and Cheetah Digital. Marigold is headquartered in Nashville, Tennessee.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$How much does Campaign Monitor cost?$q$, $q$Paid plans start at roughly $13/month for the Lite tier, scaling to about $31/month for Essentials and $171/month for Premier, with pricing increasing based on subscriber count. Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Does Campaign Monitor offer a nonprofit discount?$q$, $q$Yes, Campaign Monitor offers a 15% discount for qualifying nonprofit organizations.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Small Business Newsletters$q$, $q$Small businesses use Campaign Monitor's templates and segmentation to run regular email newsletters and promotions.$q$, $q$Small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Agency Client Management$q$, $q$Marketing agencies use Campaign Monitor to manage email campaigns for multiple clients from one account.$q$, $q$Marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Nonprofit Donor Communications$q$, $q$Nonprofits use Campaign Monitor's discounted plans to run donor newsletters and fundraising campaigns.$q$, $q$Nonprofit organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Free Trial$q$, $q$$0$q$, $q$30-day trial$q$, NULL, $q$["Up to 500 contacts","500 email sends","Limited reporting","Signup forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Lite$q$, $q$From ~$13/month$q$, $q$monthly or annual$q$, NULL, $q$["Custom templates","Signup forms","AI Writer","Transactional email","Capped monthly sends"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Essentials$q$, $q$From ~$31/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited sends","Priority support","Unlimited AI features","Optional add-ons"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Premier$q$, $q$From ~$171/month$q$, $q$monthly or annual$q$, NULL, $q$["Premier phone support","Advanced engagement segments","Send-time optimization","Website builder"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Dedicated account manager","Quarterly business reviews","Multi-brand management","Consolidated billing"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Campaign Monitor was founded in 2004 in Sydney, Australia, by Ben Richardson and Dave Greiner as a bootstrapped, designer-friendly email marketing tool. After a 2017 merger to form CM Group and further acquisitions and investment, the business was rebranded as Marigold in 2023, with Campaign Monitor continuing as its email marketing product for small and mid-market customers.$q$, $q$Marigold is headquartered in Nashville, Tennessee, after having sold its larger enterprise business to Zeta Global in 2025 while retaining Campaign Monitor.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Campaign Monitor centers on a drag-and-drop email builder with customizable templates, audience segmentation, A/B testing, and campaign analytics, plus AI-assisted email writing and behavior-triggered automation journeys.$q$, $q$Higher tiers add transactional email, send-time optimization, pre-built engagement segments, and a drag-and-drop website builder.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pricing scales with subscriber count and send volume across five tiers: a limited Free trial, Lite (from ~$13/month), Essentials (from ~$31/month, unlimited sends), Premier (from ~$171/month), and custom Enterprise pricing. A 15% discount is available for nonprofits.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
