INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Screen & Webcam Recording$q$, $q$Capture full-screen, application-specific, or webcam video for tutorials and presentations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Timeline-Based Video Editor$q$, $q$Edit recordings with a professional, multi-track timeline interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$AI-Powered Video Creation$q$, $q$AI-assisted video creation tools available on the Create tier and above.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Templates & Asset Library$q$, $q$Built-in templates, royalty-free music, and icons to speed up video production.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Interactive Quizzing$q$, $q$Add quizzes and interactive elements for e-learning content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Direct Publishing$q$, $q$Export or publish directly to YouTube, Vimeo, and learning management systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Team Collaboration$q$, $q$Team sharing and cloud storage for scaled, multi-editor video production (Pro tier).$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$All-in-one recording and editing without needing separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Large tutorial, template, and course-creator community with extensive learning resources$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Regular feature updates since moving to a subscription model$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Education and volume discounts available$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Perpetual (one-time-purchase) licenses were discontinued in October 2024; all new purchases are subscription-based$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Pricier over time than lightweight recorders like Loom for basic screen-capture needs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Desktop-only (Windows and Mac), with no official mobile recording app$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$AI video creation tools require the higher Create or Pro tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Is Camtasia free?$q$, $q$Camtasia is not free; it is subscription-based, starting at $39/year for the Starter (capture-only) plan. TechSmith previously offered perpetual licenses but discontinued them in October 2024.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Can I still buy a Camtasia perpetual license?$q$, $q$No. As of Fall 2024, TechSmith discontinued perpetual license sales; Camtasia is now available only as a subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Is Camtasia available for Mac?$q$, $q$Yes, Camtasia is available for both Windows and macOS.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$What's the difference between Camtasia Starter and Essentials?$q$, $q$Starter ($39/year) includes advanced screen capture only, while Essentials (~$180/year) adds the full video and audio editing toolkit.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Does Camtasia have AI features?$q$, $q$Yes, AI-assisted video creation tools are included starting with the Create plan ($249/year).$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Corporate E-Learning$q$, $q$Trainers and instructional designers use Camtasia to record and edit training and onboarding videos with quizzes and interactive elements.$q$, $q$Corporate trainers and L&D teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Online Course Creation$q$, $q$Educators and course creators use Camtasia to record lectures and tutorials and publish them to learning platforms.$q$, $q$Educators and online course creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Software Tutorials & IT Documentation$q$, $q$IT and support teams record software walkthroughs and how-to videos for customers and internal teams.$q$, $q$IT and support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Starter$q$, $q$$39/year$q$, $q$annual$q$, NULL, $q$["Advanced screen capture"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Essentials$q$, $q$$179.88/year$q$, $q$annual$q$, NULL, $q$["Full video and audio editing","Templates and assets"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Create$q$, $q$$249/year$q$, $q$annual$q$, NULL, $q$["AI video creation tools","All Essentials features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Pro$q$, $q$$599/year$q$, $q$annual$q$, NULL, $q$["Scaled video production","Team sharing and cloud storage"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Custom-quoted for teams and large organizations"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Camtasia is TechSmith's screen recording and video editing software, first released in 2002. TechSmith itself was founded in 1987 by Bill Hamilton and is headquartered in East Lansing, Michigan, with roughly 350 employees as of 2026.$q$, $q$As of Fall 2024, TechSmith discontinued perpetual licenses for Camtasia, moving fully to a subscription model across its Starter, Essentials, Create, Pro, and Enterprise tiers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Camtasia combines screen and webcam recording with a timeline-based video editor, including templates, royalty-free music and icon assets, quizzing and interactive elements for e-learning, and direct publishing to platforms like YouTube and learning management systems.$q$, $q$Its Create tier adds AI-assisted video creation tools, while higher tiers support team sharing and cloud storage for scaled video production.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Camtasia is priced across five annual subscription tiers: Starter ($39/year, capture only), Essentials (~$180/year, full editing), Create ($249/year, AI tools), Pro ($599/year, team production), and custom Enterprise pricing. Educational and volume discounts are available.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('217a3242-bd27-4f82-bf44-e768e2d249f8', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
