INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Ammunition Inventory Tracking$q$, $q$Catalog ammunition types and quantities across storage containers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Storage Container Organization$q$, $q$Group and label ammunition by container with custom tags.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Range Day Usage Logging$q$, $q$Stage rounds before a range day and record what was used afterward.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Multi-User Accounts$q$, $q$Support for multiple users via invite tokens or open registration, with the first user set as admin.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Self-Hosted Docker Deployment$q$, $q$Deployed via Docker Compose with configurable environment variables.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$AGPL Open-Source License$q$, $q$Fully open, auditable source code released under AGPLv3-or-later.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Free and open source under the AGPLv3-or-later license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Self-hosted design keeps sensitive firearm and ammunition data under the user's own control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Straightforward Docker Compose deployment$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Flexible tagging system for organizing inventory$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Requires self-hosting and basic Docker/server administration knowledge; no managed cloud version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Small, community-maintained project with limited formal support or onboarding$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Narrow, single-purpose feature set focused only on ammunition tracking$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Is Cannery free?$q$, $q$Yes. Cannery is free and open source under the AGPLv3-or-later license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Do I need to self-host Cannery?$q$, $q$Yes. Cannery has no managed cloud version; it must be self-hosted, typically via Docker Compose, with users providing their own server infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$What does Cannery track?$q$, $q$Cannery tracks ammunition inventory across storage containers, including staging rounds for range days and logging usage after shooting sessions.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Who maintains Cannery?$q$, $q$Cannery is maintained by a developer known as shibao, with its source code hosted on Codeberg and mirrored on other Git platforms.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Personal Ammo Inventory Tracking$q$, $q$Individual firearm owners and hobbyist shooters self-host Cannery to track ammo levels before and after range days.$q$, $q$Individual firearm owners and hobbyist shooters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$Shared Club Inventory$q$, $q$Small gun clubs or shooting groups run a shared Cannery instance to manage group-owned ammunition inventory.$q$, $q$Gun clubs and shooting groups$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cannery is a free, open-source, self-hosted application for tracking firearm ammunition inventory. Users organize ammo into storage containers, log range-day usage, and keep an ongoing view of their stock without relying on a third-party cloud service.$q$, $q$The project is maintained by a developer known as shibao, is built with Elixir, Phoenix, and PostgreSQL, and is released under the AGPLv3-or-later open-source license.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cannery supports custom tagging of containers and ammunition, staging rounds for a range day, and recording usage after shooting sessions. Multi-user accounts can be enabled with either invite tokens or open public registration.$q$, $q$The application is deployed via Docker Compose, with configuration handled through environment variables and an optional reverse proxy for HTTPS.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c31deb25-5ad3-4424-a471-a168e2a0264c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cannery is free and open source under the AGPLv3-or-later license, with no paid tiers. Users only bear the cost of the server infrastructure they choose to self-host it on.$q$]::text[], 2);
