-- Enrichment marathon batch: Cal.com, Calagopus, Calday, Calendly, Calibre, Campaign Monitor, Camtasia, Cannery

-- ── Cal.com ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cal.com is a developer-friendly scheduling platform for booking meetings, syncing calendars, and automating team availability, used by individuals through enterprises.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $12/month per user)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$~40 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cal.com Review 2026: Features, Pricing & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Cal.com is a scheduling platform with unlimited event types, round-robin booking, and 100+ integrations. See 2026 pricing, features, and pros/cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cal.com is a scheduling and booking platform founded in 2021 by Peer Richelsen and Bailey Pumfleet, initially launched as Calendso before rebranding after acquiring the cal.com domain later that year. The company is headquartered in San Francisco and employs roughly 40 people. Cal.com raised approximately $32.4 million in funding, including a $25 million Series A led by Seven Seven Six in April 2022 that valued the company at $150 million; other investors include OSS Capital. Cal.com was built on a commercial open-source (COSS) model, combining a free self-hostable codebase with paid hosted cloud and enterprise tiers, and it grew a large developer community around its AGPL-licensed repository. In April 2026, Cal.com announced it was moving its core hosted product from an open-source license to a proprietary one, citing concerns that AI-assisted code scanning made publicly visible source code easier for attackers to exploit; the company said it would keep security-critical components open under a new MIT-licensed project called Cal.diy, describing the move as a continuation rather than an abandonment of its open-source roots. The decision drew criticism from parts of the open-source community, including skepticism about whether security was the primary motivation. Functionally, Cal.com lets users and teams create unlimited event types and booking pages, supports collective and round-robin scheduling for teams, and offers workflow automation, custom notifications, and routing forms for qualifying inbound leads. It integrates with over 100 apps, including Google Calendar, Outlook, Zoom, Stripe, PayPal, Salesforce, and HubSpot, and exposes an API and embeddable widgets so developers can build scheduling directly into their own products. Native iOS and Android apps, branded 'Cal.com Companion,' let users manage bookings and receive push notifications on mobile devices; the iOS app requires iOS 15.1 or later. Pricing has four tiers: Free ($0, one user, unlimited event types and calendars, 100+ integrations, mobile app); Teams ($12/month per user billed annually, roughly 25% cheaper than monthly billing, with a 14-day free trial), which adds team scheduling, round-robin routing, managed event types, and API access; Organizations ($28/month per user billed annually, also with a 14-day trial), which adds unlimited sub-teams, SAML SSO, SCIM provisioning, custom subdomains, and SOC 2, HIPAA, and ISO 27001 compliance options; and Enterprise, with custom pricing for dedicated support, SLAs, and HRIS integrations. Cal.com competes most directly with Calendly and positions itself toward technical teams, agencies, and companies that want deeper customization, self-branding, or compliance controls than typical consumer scheduling tools provide. It is commonly used for sales demo booking, recruiting and interview scheduling, customer support scheduling, and embedding booking flows inside SaaS products via its developer platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aee8fc7c-2bc5-4e1a-ba70-2a8958f81cc7';

