-- ── Calagopus ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Calagopus is a free, open-source game server management panel built in Rust for deploying, monitoring, and administering Minecraft, Rust, and other multiplayer servers.$q$, short_description),
  pricing_model = COALESCE($q$Free (open-source)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2025, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Calagopus: Free Open-Source Game Server Panel$q$, seo_title),
  seo_meta_description = COALESCE($q$Calagopus is a self-hosted, open-source Rust game server panel and Pterodactyl alternative. See features, licensing, and setup details.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Calagopus is a free, open-source game server management panel positioned as a modern, ground-up alternative to the widely used Pterodactyl Panel. Rather than reusing Pterodactyl's PHP-based stack, Calagopus was rewritten from scratch in Rust for the backend with a React frontend, a choice its documentation and marketing materials attribute to major gains in throughput and memory efficiency compared to PHP-based panels. Its GitHub repository (calagopus/panel) shows the project publicly active since 2025, with a steady stream of point releases (versions such as 1.0.2 through 1.0.11 as of mid-2026) maintained under the calagopus GitHub organization. The software is self-hosted: operators run the web-based panel component on Windows, Linux, or via Docker, while the server-side component (called Wings, following Pterodactyl terminology) requires a Linux host to run the actual containerized game servers. Calagopus supports ARM64 architectures, including Raspberry Pi deployments, which makes it accessible to hobbyists running small home lab setups as well as larger commercial game-hosting operators. Each managed game server runs in an isolated Docker container, which the project frames as a core part of its security model alongside general secure-web-application practices for the panel itself. Calagopus uses an 'egg' system, borrowed conceptually from Pterodactyl, to define how different games and server software are installed and configured; because Calagopus aims for compatibility with existing Pterodactyl egg presets, administrators migrating from Pterodactyl can reuse much of their existing configuration rather than starting over, and the project provides migration tooling to ease that transition. The panel is designed to be extensible, offering a plugin system built on Rust traits so developers can add custom functionality to both the frontend and backend rather than being limited to what ships in the base install. Calagopus is free for both personal and commercial use with no feature gating, no subscription tiers, and no license fees, which is consistent with its MIT-licensed core components (individual repositories in the project may carry their own specific license terms). Because it is a self-hosted, open-source project rather than a company with a commercial product, there is no publicly disclosed company size, headquarters, or funding history; support and development activity are coordinated through its GitHub organization and a Discord community server rather than a formal sales or support organization. Calagopus is aimed at game server hosting providers, Minecraft and Rust community operators, and homelab enthusiasts who want a faster, lower-resource-footprint alternative to established panels like Pterodactyl, particularly those comfortable administering their own Docker and Linux infrastructure. As a relatively young project, it has a smaller track record and community size than more established, years-old panel software, which is a consideration for operators evaluating long-term stability and support before migrating production game-hosting infrastructure onto it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5950887b-56e9-4a05-b6d2-f57b3d882853';

