-- ── Calendly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Calendly is a widely used scheduling platform that lets individuals and teams share booking links, automate meeting workflows, and sync calendars across tools.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Standard plan from $10/month per seat, billed annually)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$~500 employees$q$, company_size),
  headquarters = COALESCE($q$Atlanta, Georgia, USA (remote-first since 2021)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Calendly Review 2026: Features, Pricing & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Calendly is a scheduling app with group events, routing forms, and workflow automation. Compare 2026 pricing plans, features, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Calendly is a scheduling and meeting-automation platform founded in 2013 in Atlanta, Georgia, by Nigerian-born entrepreneur Tope Awotona, who bootstrapped the company for several years before raising venture funding. Calendly grew into one of the best-known names in online scheduling, reaching a reported $3 billion valuation around a 2021 funding round and roughly 10 million users. The company closed its physical Atlanta headquarters in July 2021 and moved to a remote-first operating model, though it remains headquartered in the Atlanta area; employee count estimates for 2026 range from roughly 380 to 545 depending on the data source, with most estimates clustering around 500. Calendly's core product lets users create single or group event types and share a personal booking link so others can pick an open time slot without back-and-forth emails; it automatically checks the user's connected calendar for conflicts. Beyond individual booking links, Calendly supports team-based scheduling features such as round-robin distribution and collective (panel) scheduling, routing forms that qualify and direct inbound leads to the right rep, and workflow automation that can send reminder emails, follow-ups, and custom notifications tied to booking events. It integrates with a broad set of business tools, including Google Calendar, Outlook, Zoom, Salesforce, and HubSpot, and offers a browser extension and embeddable widgets for adding scheduling links to emails and websites. Calendly is available as a free mobile app for both iOS and Android, accessible to users on every plan, letting them book, reschedule, and manage availability from a phone. Pricing is structured in four tiers. The Free plan supports one event type with unlimited meetings, a single connected calendar, basic integrations, booking page customization, confirmation emails, website embedding, and access to the mobile app and browser extension. The Standard plan costs $12 per month per seat billed monthly, or $10 per month per seat billed annually, and adds features suited to individuals who need more scheduling flexibility. The Teams plan costs $20 per month per seat billed monthly (for 1–30 seats), dropping to $16 per month per seat with annual billing, and is designed for teams that need round-robin and collective scheduling plus shared workflows. The Enterprise plan is built for large organizations that require single sign-on, audit logging, dedicated implementation support, or the full Salesforce routing suite, with custom, negotiated pricing based on organizational needs. Calendly is most commonly used by sales teams booking demos and discovery calls, recruiters scheduling candidate interviews, customer success and support teams coordinating client meetings, and individual professionals such as consultants, coaches, and freelancers managing client bookings, competing most directly with tools like Cal.com in the online scheduling category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a69c9e8e-2b63-4936-9731-f85ffcfa1860';

