-- ── Calibre ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Calibre is a free, open-source e-book library manager that lets users organize, convert between formats, edit, and sync e-books to devices like Kindle and Kobo.$q$, short_description),
  pricing_model = COALESCE($q$Free (open-source)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Mumbai, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Calibre: Free Open-Source E-Book Manager (2026 Guide)$q$, seo_title),
  seo_meta_description = COALESCE($q$Calibre is a free, open-source e-book manager for converting, editing, and organizing books across Kindle, Kobo, and other devices. See features and history.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Calibre is a free, open-source e-book management application originally created by Kovid Goyal, a graduate student at the time, who launched the project on October 31, 2006. It began as a small utility called libprs500, built to work around the fact that Sony's newly released PRS-500 e-reader had no Linux support; Goyal reverse-engineered its USB protocol with help from the mobileread.com community. The tool's first purpose was converting popular e-book formats into Sony's proprietary LRF format for that reader, which was later adopted by some publishing houses. A graphical library-management interface was added next, and by mid-2008 the project had grown into a full e-book management platform and was renamed calibre — a name chosen by Goyal's wife, Krittika, with 'libre' signaling its free and open-source nature. Goyal, based in Mumbai, India, remains the primary developer, supported by what the project describes as a small core team of around half a dozen developers plus many community testers and translators across more than 200 countries; the interface has been translated into more than a dozen languages by volunteers. Calibre is built on open-source libraries and runs natively on Windows, macOS, and Linux. Functionally, calibre works as a comprehensive e-book hub: it manages a personal library with searchable metadata, converts books between formats such as EPUB, MOBI, AZW3, and PDF, includes a built-in e-book viewer and an editor for tweaking formatting, fonts, margins, and auto-generated tables of contents, and can fetch metadata and cover art for books automatically from the internet. It can also download online news sources and periodicals and convert them into e-book format for offline reading. Calibre syncs books to a wide range of e-reader hardware, including Kindle, Kobo, and Nook devices, and offers an optional content server component that can be self-hosted to give remote, browser-based access to a user's library from other devices. A recent major release (version 9.x, referenced as of 2026) added a new 'Bookshelf' library view that displays books spine-out on virtual shelves, similar to a physical bookcase. The software's extensibility comes in part from a plugin architecture that lets developers and power users add custom functionality, such as third-party plugins for tasks like machine-translating an entire e-book. Because calibre is completely free with no paid tiers, subscriptions, or licensing fees, it has no formal pricing plans, company size, or corporate headquarters in the conventional sense — it operates as a long-running, largely volunteer open-source project rather than a commercial software company. It is widely used by personal e-book collectors managing large libraries, independent and self-published authors converting manuscripts between formats for different retailers and devices, and institutions such as libraries that need a free, cross-platform way to manage and distribute digital text collections.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3e99368f-6adc-431d-9ed6-588c0d07395e';

