-- ── Campaign Monitor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Campaign Monitor is an email marketing platform for building, automating, and analyzing email campaigns, now operated by Marigold as part of its marketing suite.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (tiered by subscriber count)$q$, pricing_model),
  starting_price = COALESCE($q$From about $13/month (Lite plan)$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$~100-250 employees (Campaign Monitor division of Marigold)$q$, company_size),
  headquarters = COALESCE($q$Nashville, Tennessee, USA (Marigold HQ); originally founded in Sydney, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Campaign Monitor Review 2026: Pricing, Features & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Campaign Monitor is an email marketing platform with drag-and-drop templates and automation. See 2026 pricing tiers, features, and pros/cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Campaign Monitor is an email marketing platform founded in 2004 in Sydney, Australia, by Ben Richardson and Dave Greiner, who bootstrapped the company around designer-friendly email tools before it grew into one of the more established players in the email marketing category. In 2017, investment firm Insight Partners merged Campaign Monitor with fellow email platform Emma to form CM Group, which then acquired Sailthru and Liveclicker in 2019 to add real-time personalization and enterprise data capabilities, expanding beyond its original small-and-medium-business focus. Further investment from Wellspring Capital Management and TA Associates in 2021 funded additional consolidation, and in 2022 CM Group merged with Cheetah Digital; in 2023 the combined company was rebranded as Marigold, a unified relationship-marketing platform. Marigold is headquartered in Nashville, Tennessee, and in 2025 sold its larger enterprise business to Zeta Global while retaining Campaign Monitor to continue serving small and mid-market customers under the Marigold umbrella. Employee estimates for the Campaign Monitor division specifically range from roughly 100 to 240 depending on the data source. Campaign Monitor's core product centers on a drag-and-drop email builder with a library of customizable templates, list segmentation, A/B testing, and campaign analytics and reporting. It has added AI-assisted email writing tools and marketing automation journeys that trigger emails based on subscriber behavior. Pricing is tiered primarily by subscriber count and monthly send volume. A Free plan supports up to 500 contacts and 500 email sends as a 30-day trial with limited reporting and signup forms. The paid Lite plan starts at roughly $13 per month for a capped number of monthly sends and includes core features like custom templates, signup forms, an AI writer, and transactional email. The Essentials plan, marketed as the best-value tier, starts at roughly $31 per month and unlocks unlimited email sends, priority support, and unlimited access to AI-powered email features, along with optional paid add-ons such as non-human click filtering and pre-built engagement segments. The Premier plan starts at roughly $171 per month (some listings show a lower promotional starting price) and adds premier-level phone support, advanced pre-built engagement segments, send-time optimization, email section locking, and a drag-and-drop website builder. An Enterprise tier offers custom, volume-based pricing with a dedicated account manager, quarterly business reviews, multi-brand account management, and consolidated billing across brands. Campaign Monitor also offers a 15% discount for qualifying nonprofit organizations and additional savings for customers who switch from monthly to annual billing. The platform is commonly used by small and mid-sized businesses running newsletters and promotional campaigns, marketing agencies managing email for multiple clients under one account, and nonprofits running donor communications, though its per-subscriber pricing structure means costs can rise quickly as an email list grows compared to some flat-rate competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
