-- ── Camtasia ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Camtasia is TechSmith's screen recording and video editing software for creating tutorials, presentations, and training videos on Windows and Mac.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$39/year (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2002, founded_year),
  company_size = COALESCE($q$~350 employees (TechSmith)$q$, company_size),
  headquarters = COALESCE($q$East Lansing, Michigan, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Camtasia Review 2026: Pricing, Features & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Camtasia is TechSmith's screen recording and video editing software. See 2026 subscription pricing, features, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Camtasia is screen recording and video editing software made by TechSmith, a private software company founded in 1987 by Bill Hamilton and headquartered in East Lansing, Michigan, on the Michigan State University Research Park since 2021, with roughly 350 employees as of 2026. TechSmith began as a custom software development firm before pivoting toward commercial screen-capture products in the mid-1990s, first with Snagit and later with Camtasia, which was first released in 2002 for Windows before a Mac version followed. Camtasia has been continuously updated since then; early versions recorded video in an AVI container using TechSmith's own TSCC codec, version 3 introduced the proprietary CAMREC container format, and version 8.4 moved to an MPEG-4-based TREC format, reflecting the software's gradual evolution from a simple screen recorder into a full timeline-based video editor. Across its history, TechSmith states that its products, including Camtasia and Snagit, have been used to create billions of images and videos by more than 73 million people in over 190 countries. As of Fall 2024, TechSmith discontinued perpetual (one-time-purchase) licenses for Camtasia, with the last opportunity to buy a perpetual license at upgrade pricing falling on October 1, 2024; all new purchases are now subscription-based. Camtasia's current pricing spans five tiers. The Starter plan costs $39 per year and provides advanced screen capture without the full editing suite. The Essentials plan costs about $179.88 per year (roughly $15/month) and adds the full video and audio editing toolkit. The Create plan costs $249 per year and layers in AI-assisted video creation tools. The Pro plan costs $599 per year and is aimed at scaled video production for teams. Enterprise pricing is custom-quoted for larger organizations; TechSmith also offers volume discounts, with reports of $140-160 per user per year for 20-50 license purchases and $90-120 per user per year for 100+ seat enterprise deployments, plus an educational discount around $169 for teachers, students, and institutions. Functionally, Camtasia combines screen and webcam recording with a timeline-based editor that supports templates, royalty-free music and icon assets, quizzing and interactive elements for e-learning content, and direct publishing to platforms like YouTube, Vimeo, and learning management systems. The newer Create tier adds AI-powered video creation capabilities. Camtasia is desktop software for Windows and macOS with no official mobile recording app, and it is most heavily used by corporate trainers and instructional designers producing e-learning content, educators and online course creators recording lecture or tutorial videos, and IT and support teams creating software walkthroughs and how-to videos, competing in the same category as tools like Loom, ScreenFlow, and OBS Studio combined with editing software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '217a3242-bd27-4f82-bf44-e768e2d249f8';

