-- ── Cannery ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cannery is a free, open-source, self-hosted app for tracking firearm ammunition inventory, storage containers, and range-day usage.$q$, short_description),
  pricing_model = COALESCE($q$Free (open-source)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cannery: Free Self-Hosted Ammo Inventory Tracker$q$, seo_title),
  seo_meta_description = COALESCE($q$Cannery is an open-source, self-hosted app for tracking ammunition inventory and range-day usage. See features, license, and setup details.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cannery is a free, open-source, self-hosted web application built specifically for tracking firearm ammunition inventory. It lets users create storage containers, catalog different types and calibers of ammunition, organize inventory into ammo packs, stage rounds ahead of a range day, and record how much ammunition was used during shooting sessions, giving owners an ongoing view of their ammo levels before and after they go to the range. The project is maintained by a developer known as shibao (also referenced as shibaobun), with its primary source repository hosted on Codeberg (shibao/cannery) and mirrored on other Git hosting platforms, including a Gitea instance. Cannery is built with the Elixir programming language on the Phoenix web framework, backed by a PostgreSQL database, and is released under the GNU Affero General Public License version 3 or later (AGPLv3+), a copyleft license that guarantees the source code and any modifications remain open and available to users, including when the software is run as a network service. Because Cannery is self-hosted, there is no managed cloud version operated by the maintainer; instead, users deploy their own instance, most commonly using Docker Compose or Docker Desktop. Setup involves copying an example docker-compose.yml file, configuring environment variables such as HOST (the external URL used to generate links), DATABASE_URL (defaulting to a bundled PostgreSQL container), and a generated SECRET_KEY_BASE used to sign cookies, then starting the stack with a docker-compose command; operators typically add a reverse proxy, such as Nginx Proxy Manager, in front of the application to handle HTTPS and routing. The first user created on a new Cannery instance automatically becomes an administrator, and instance owners can choose whether to leave registration open to the public or restrict new accounts to invite tokens. Additional organizational features include custom tagging for containers and ammunition to help users build their own categorization scheme rather than being locked into a fixed structure. Because Cannery is a small, community-maintained open-source project rather than a commercial company, there is no publicly disclosed company size, headquarters, funding history, or formal pricing plan — it is free to use and free to modify under its AGPL license, with the only real cost being the server or hosting infrastructure an operator chooses to run it on. Cannery is aimed at a niche but specific audience: individual firearm owners and hobbyist or competitive shooters who want to track their ammunition inventory and usage over time without handing that data to a third-party cloud service, as well as small gun clubs or shooting groups that want a shared, self-hosted inventory system. Its self-hosted, privacy-oriented design is the core differentiator versus any consumer inventory or spreadsheet-based alternative, at the cost of requiring users to have basic comfort with Docker and self-hosting workflows to get it running.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c31deb25-5ad3-4424-a471-a168e2a0264c';

